SELECT
    COALESCE(SUM(ed.amount), 0) AS totalExpense,
    COUNT(CASE WHEN cr.record_type_code = 'MEDICAL' THEN 1 END) AS medicalCount,
    (
        SELECT COUNT(*)
        FROM public.care_record_medical_details md2
        JOIN public.care_records cr2 ON md2.care_record_id = cr2.id
        WHERE cr2.user_id = #{userId}
        AND cr2.dog_id = #{dogId}
        AND md2.medication_start_date <= #{today}
        AND (md2.medication_start_date + (md2.medication_days || ' days')::interval) >= #{today}
        AND md2.is_medication_completed = false
    ) AS activeMedicationCount,
    (
        SELECT COUNT(*)
        FROM public.schedules s
        JOIN public.dogs d2 ON s.dog_id = d2.id
        WHERE d2.user_id = #{userId}
        AND s.dog_id = #{dogId}
        AND s.schedule_date >= #{today}
    ) AS upcomingScheduleCount
FROM public.care_records cr
LEFT JOIN public.care_record_expense_details ed ON cr.id = ed.care_record_id
WHERE cr.user_id = #{userId}
AND cr.dog_id = #{dogId}
AND cr.record_date BETWEEN #{startDate} AND #{endDate}
